import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.B9unkguw.js";const p=JSON.parse('{"title":"Log Viewer (Analyze View)","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qgc-user-guide/analyze_view/log_viewer.md","filePath":"zh/qgc-user-guide/analyze_view/log_viewer.md"}'),l={name:"zh/qgc-user-guide/analyze_view/log_viewer.md"};function i(n,e,s,h,d,g){return a(),o("div",null,e[0]||(e[0]=[r('<h1 id="log-viewer-analyze-view" tabindex="-1">Log Viewer (Analyze View) <a class="header-anchor" href="#log-viewer-analyze-view" aria-label="Permalink to &quot;Log Viewer (Analyze View)&quot;">​</a></h1><p>The <em>Log Viewer</em> screen (<strong>Analyze &gt; Log Viewer</strong>) is a unified post-flight analysis tool that supports three log formats:</p><table tabindex="0"><thead><tr><th>Format</th><th>Extension</th><th>Firmware</th></tr></thead><tbody><tr><td>ArduPilot DataFlash</td><td><code>.bin</code> / <code>.log</code></td><td>ArduPilot (ArduCopter, ArduPlane, ArduRover, ArduSub)</td></tr><tr><td>PX4 ULog</td><td><code>.ulg</code></td><td>PX4</td></tr><tr><td>MAVLink Telemetry</td><td><code>.tlog</code></td><td>Any</td></tr></tbody></table><h2 id="opening-a-log" tabindex="-1">Opening a Log <a class="header-anchor" href="#opening-a-log" aria-label="Permalink to &quot;Opening a Log&quot;">​</a></h2><p>Use the <strong>Open .bin</strong>, <strong>Open .ulg</strong>, or <strong>Open .tlog</strong> button at the top of the screen to select a log file. Click <strong>Clear</strong> to unload the current log.</p><p>The filename of the loaded log is shown in the toolbar to the right of the buttons.</p><h2 id="firmware-log-analysis-bin-ulg" tabindex="-1">Firmware Log Analysis (.bin / .ulg) <a class="header-anchor" href="#firmware-log-analysis-bin-ulg" aria-label="Permalink to &quot;Firmware Log Analysis (.bin / .ulg)&quot;">​</a></h2><p>When a DataFlash or ULog file is loaded the screen shows four tabs: <strong>Charting</strong>, <strong>Map</strong>, <strong>Parameters</strong>, and <strong>Messages</strong>.</p><h3 id="charting-tab" tabindex="-1">Charting Tab <a class="header-anchor" href="#charting-tab" aria-label="Permalink to &quot;Charting Tab&quot;">​</a></h3><p>The left panel shows summary information (field count, parameter count, event count, detected vehicle type) and a searchable list of all plottable fields.</p><ul><li>Toggle a field on or off using the slider next to its name.</li><li>Use the <strong>Search fields</strong> box to filter by name.</li><li>Click <strong>Clear Selected</strong> to remove all plotted fields at once.</li></ul><p>The right panel shows a time-series chart of all selected fields. Each field is plotted on its own auto-scaled Y axis. Moving the cursor over the chart shows a popup with the current, minimum, and maximum value for each field, as well as the current flight mode. Drag horizontally to zoom in; right-click to reset zoom.</p><h3 id="map-tab" tabindex="-1">Map Tab <a class="header-anchor" href="#map-tab" aria-label="Permalink to &quot;Map Tab&quot;">​</a></h3><p>The Map tab displays the GPS flight path overlaid on a map, with the path auto-fitted to the screen on load.</p><p>For ArduPilot logs the path is derived from the <code>GPS</code> message (requires a valid 3D fix). For PX4 ULog the path comes from <code>vehicle_global_position</code>.</p><p>An altitude mini-chart is shown below the map when GPS altitude data is available. Click or drag on the altitude chart to move a position marker (yellow dot) along the flight path on the map. Drag horizontally on the altitude chart to zoom in on a time range; right-click to reset. The altitude popup shows the current, minimum, and maximum altitude for the full log.</p><p>The map cursor is linked to the charting tab: moving the cursor in either the main chart or the altitude chart updates the marker position in both places.</p><h3 id="parameters-tab" tabindex="-1">Parameters Tab <a class="header-anchor" href="#parameters-tab" aria-label="Permalink to &quot;Parameters Tab&quot;">​</a></h3><p>Lists all parameters recorded in the log. By default only parameters that differ from their system default are shown; toggle <strong>Changed only</strong> to see all parameters. Use the search box to filter by name, value, or description. Parameters that differ from their default are shown in bold with an orange indicator dot and the default value alongside.</p><h3 id="messages-tab" tabindex="-1">Messages Tab <a class="header-anchor" href="#messages-tab" aria-label="Permalink to &quot;Messages Tab&quot;">​</a></h3><p>Lists all status messages from the log (ArduPilot <code>MSG</code> messages or PX4 equivalent) in chronological order with timestamps.</p><h2 id="telemetry-log-analysis-tlog" tabindex="-1">Telemetry Log Analysis (.tlog) <a class="header-anchor" href="#telemetry-log-analysis-tlog" aria-label="Permalink to &quot;Telemetry Log Analysis (.tlog)&quot;">​</a></h2><p>When a <code>.tlog</code> file is loaded the <strong>Charting</strong> tab shows a playback control bar in the left panel.</p><table tabindex="0"><thead><tr><th>Control</th><th>Function</th></tr></thead><tbody><tr><td><strong>Play / Pause</strong></td><td>Start or pause log replay</td></tr><tr><td>Speed selector</td><td>Set replay speed (0.1× – 10×)</td></tr><tr><td>Seek slider</td><td>Jump to any point in the log</td></tr><tr><td>Time display</td><td>Shows current and total log duration</td></tr></tbody></table><p>While replaying, all live vehicle data views (HUD, instruments, MAVLink Inspector) update as if the vehicle were connected. The right panel of the Charting tab shows a live MAVLink Inspector for the replaying vehicle.</p><h2 id="typical-workflow" tabindex="-1">Typical Workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical Workflow&quot;">​</a></h2><ol><li>Download logs from <strong>Analyze &gt; Log Download</strong>.</li><li>Open the downloaded <code>.bin</code>, <code>.ulg</code>, or <code>.tlog</code> in <strong>Analyze &gt; Log Viewer</strong>.</li><li>For firmware logs: select fields of interest in the left panel and inspect the chart, map, parameters, and messages.</li><li>For telemetry logs: use the playback controls to step through the flight.</li></ol>',27)]))}const m=t(l,[["render",i]]);export{p as __pageData,m as default};
